 60 ConstantRange ConstantRange::fromKnownBits(const KnownBits &Known,
 61                                            bool IsSigned) {
 62   if (Known.hasConflict())
 63     return getEmpty(Known.getBitWidth());
 64   if (Known.isUnknown())
 65     return getFull(Known.getBitWidth());
