 73   // and the upper bound as a non-negative one.
 74   APInt Lower = Known.getMinValue(), Upper = Known.getMaxValue();
 75   Lower.setSignBit();
 76   Upper.clearSignBit();
 77   return ConstantRange(Lower, Upper + 1);
